// PrГіximos partidos de MГ©xico вҖ” timestamps UTC
const PROXIMO_MX = [
  { after_date: '2026-06-11', utc_ts: 1781830800, h: 'MГ©xico', hf: 'рҹҮІрҹҮҪ', a: 'Corea del Sur', af: 'рҹҮ°рҹҮ·', d: 'MiГ© 18 jun', v: 'Estadio Akron, Guadalajara' },
  { after_date: '2026-06-18', utc_ts: 1782349200, h: 'Chequia', hf: 'рҹҮЁрҹҮҝ', a: 'MГ©xico', af: 'рҹҮІрҹҮҪ', d: 'Mar 24 jun', v: 'Estadio Azteca, CDMX' },
];
function getNextMx() {
  const today = new Date().toISOString().slice(0, 10);
  return PROXIMO_MX.filter(m => m.after_date >= today).sort((a, b) => a.utc_ts - b.utc_ts)[0] || null;
}


const data     = $input.first().json;
const fixtures = data.response || [];
const sd       = $getWorkflowStaticData('node');
const globalSd = $getWorkflowStaticData('global');
const events   = [];

const FLAGS = {
  'Mexico':'рҹҮІрҹҮҪ','MГ©xico':'рҹҮІрҹҮҪ','South Africa':'рҹҮҝрҹҮҰ','SudГЎfrica':'рҹҮҝрҹҮҰ',
  'Spain':'рҹҮӘрҹҮё','EspaГұa':'рҹҮӘрҹҮё','Peru':'рҹҮөрҹҮӘ','PerГә':'рҹҮөрҹҮӘ',
  'Brazil':'рҹҮ§рҹҮ·','Brasil':'рҹҮ§рҹҮ·','Argentina':'рҹҮҰрҹҮ·','Germany':'рҹҮ©рҹҮӘ','Alemania':'рҹҮ©рҹҮӘ',
  'France':'рҹҮ«рҹҮ·','Francia':'рҹҮ«рҹҮ·','England':'рҹҸҙу Ғ§у Ғўу ҒҘу Ғ®у Ғ§у Ғҝ','Portugal':'рҹҮөрҹҮ№',
  'Netherlands':'рҹҮірҹҮұ','Belgium':'рҹҮ§рҹҮӘ','BГ©lgica':'рҹҮ§рҹҮӘ',
  'Italy':'рҹҮ®рҹҮ№','Italia':'рҹҮ®рҹҮ№','Croatia':'рҹҮӯрҹҮ·','Croacia':'рҹҮӯрҹҮ·',
  'Uruguay':'рҹҮәрҹҮҫ','Colombia':'рҹҮЁрҹҮҙ','Chile':'рҹҮЁрҹҮұ','Ecuador':'рҹҮӘрҹҮЁ',
  'USA':'рҹҮәрҹҮё','United States':'рҹҮәрҹҮё','Canada':'рҹҮЁрҹҮҰ','CanadГЎ':'рҹҮЁрҹҮҰ',
  'Japan':'рҹҮҜрҹҮө','JapГіn':'рҹҮҜрҹҮө','South Korea':'рҹҮ°рҹҮ·','Korea Republic':'рҹҮ°рҹҮ·',
  'Morocco':'рҹҮІрҹҮҰ','Marruecos':'рҹҮІрҹҮҰ','Senegal':'рҹҮёрҹҮі',
  'Saudi Arabia':'рҹҮёрҹҮҰ','Arabia Saudita':'рҹҮёрҹҮҰ',
  'Qatar':'рҹҮ¶рҹҮҰ','Iran':'рҹҮ®рҹҮ·','Australia':'рҹҮҰрҹҮә','Poland':'рҹҮөрҹҮұ','Polonia':'рҹҮөрҹҮұ',
  'Switzerland':'рҹҮЁрҹҮӯ','Suiza':'рҹҮЁрҹҮӯ','Denmark':'рҹҮ©рҹҮ°','Dinamarca':'рҹҮ©рҹҮ°',
  'Serbia':'рҹҮ·рҹҮё','Ukraine':'рҹҮәрҹҮҰ','Ucrania':'рҹҮәрҹҮҰ','Tunisia':'рҹҮ№рҹҮі','TГәnez':'рҹҮ№рҹҮі',
  'Nigeria':'рҹҮірҹҮ¬','Ghana':'рҹҮ¬рҹҮӯ','Cameroon':'рҹҮЁрҹҮІ','CamerГәn':'рҹҮЁрҹҮІ',
  'Costa Rica':'рҹҮЁрҹҮ·','Panama':'рҹҮөрҹҮҰ','PanamГЎ':'рҹҮөрҹҮҰ','Honduras':'рҹҮӯрҹҮі',
  'El Salvador':'рҹҮёрҹҮ»','Guatemala':'рҹҮ¬рҹҮ№','Bolivia':'рҹҮ§рҹҮҙ','Paraguay':'рҹҮөрҹҮҫ',
  'Venezuela':'рҹҮ»рҹҮӘ','Indonesia':'рҹҮ®рҹҮ©','New Zealand':'рҹҮірҹҮҝ',
  'Vanuatu':'рҹҮ»рҹҮә','Fiji':'рҹҮ«рҹҮҜ','Philippines':'рҹҮөрҹҮӯ','Thailand':'рҹҮ№рҹҮӯ',
  'China':'рҹҮЁрҹҮі','India':'рҹҮ®рҹҮі','UAE':'рҹҮҰрҹҮӘ','Russia':'рҹҮ·рҹҮә',
  'Hungary':'рҹҮӯрҹҮә','Romania':'рҹҮ·рҹҮҙ','Greece':'рҹҮ¬рҹҮ·','Turkey':'рҹҮ№рҹҮ·',
  'Scotland':'рҹҸҙу Ғ§у Ғўу Ғіу ҒЈу Ғҙу Ғҝ','Wales':'рҹҸҙу Ғ§у Ғўу Ғ·у Ғ¬у Ғіу Ғҝ','Ireland':'рҹҮ®рҹҮӘ','Republic of Ireland':'рҹҮ®рҹҮӘ',
  'Austria':'рҹҮҰрҹҮ№','Sweden':'рҹҮёрҹҮӘ','Norway':'рҹҮірҹҮҙ','Finland':'рҹҮ«рҹҮ®',
  'Czech Republic':'рҹҮЁрҹҮҝ','Slovakia':'рҹҮёрҹҮ°','Slovenia':'рҹҮёрҹҮ®',
  'North Macedonia':'рҹҮІрҹҮ°','Albania':'рҹҮҰрҹҮұ','Montenegro':'рҹҮІрҹҮӘ',
  'Azerbaijan':'рҹҮҰрҹҮҝ','Georgia':'рҹҮ¬рҹҮӘ','Armenia':'рҹҮҰрҹҮІ','Belarus':'рҹҮ§рҹҮҫ',
  'Kazakhstan':'рҹҮ°рҹҮҝ','Lithuania':'рҹҮұрҹҮ№','Latvia':'рҹҮұрҹҮ»','Estonia':'рҹҮӘрҹҮӘ',
  'Angola':'рҹҮҰрҹҮҙ','Togo':'рҹҮ№рҹҮ¬','Benin':'рҹҮ§рҹҮҜ','Liberia':'рҹҮұрҹҮ·',
  'Congo DR':'рҹҮЁрҹҮ©','Ethiopia':'рҹҮӘрҹҮ№','Rwanda':'рҹҮ·рҹҮј','Kenya':'рҹҮ°рҹҮӘ',
  'Zimbabwe':'рҹҮҝрҹҮј','Zambia':'рҹҮҝрҹҮІ','Botswana':'рҹҮ§рҹҮј',
  'Sierra Leone':'рҹҮёрҹҮұ','Mauritania':'рҹҮІрҹҮ·','Myanmar':'рҹҮІрҹҮІ',
  'Cambodia':'рҹҮ°рҹҮӯ','Hong Kong':'рҹҮӯрҹҮ°','Syria':'рҹҮёрҹҮҫ','Iraq':'рҹҮ®рҹҮ¶',
  'Jordan':'рҹҮҜрҹҮҙ','Kuwait':'рҹҮ°рҹҮј','Bahrain':'рҹҮ§рҹҮӯ','Oman':'рҹҮҙрҹҮІ'
};

function flag(name) { return FLAGS[name] || 'вҡҪ'; }

function minStr(e) {
  const extra = e.time?.extra;
  return extra ? `${e.time.elapsed}+${extra}'` : `${e.time?.elapsed || 0}'`;
}

function expandName(fixtureId, name) {
  if (!name) return name;
  const nm = globalSd[`nm_${fixtureId}`] || {};
  return nm[name] || name;
}

// в”Җв”Җ Narrativa compacta (1-2 frases) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function buildNarrative(scorer, assist, detail, minute, scoring, home, away, hs, as_) {
  const diff   = Math.abs(hs - as_);
  const isLocal = scoring === home;
  const team   = isLocal ? 'local' : 'visitante';
  let accion;
  if (detail === 'Header')
    accion = assist
      ? `Centro de ${assist} y ${scorer} conecta de cabeza sin dar opciГіn al portero.`
      : `${scorer} se anticipa en el ГЎrea y convierte de cabeza con instinto goleador.`;
  else if (detail === 'Penalty')
    accion = `${scorer} ejecuta el penal con total frialdad y no falla desde los doce pasos.`;
  else if (detail === 'Free Kick' || detail === 'Freekick')
    accion = `${scorer} cobra el tiro libre con maestrГӯa y la pelota se clava en la escuadra.`;
  else if (detail === 'Own Goal')
    accion = `Desafortunado desvГӯo en propia puerta que sentencia la jugada.`;
  else
    accion = assist
      ? `${assist} asiste y ${scorer} define con precisiГіn ante el arquero rival.`
      : `${scorer} recibe, se acomoda y dispara inapelable para el portero.`;

  let contexto;
  if (minute <= 10)           contexto = `El gol tempranero obliga al rival a replantear desde el inicio.`;
  else if (minute >= 86)      contexto = `Golazo sobre la bocina que puede ser definitivo.`;
  else if (hs === as_)        contexto = `El marcador queda igualado y todo se decide en los minutos que restan.`;
  else if (diff === 1 && hs + as_ === 1) contexto = `Se abre el marcador y el partido entra en una nueva dimensiГіn.`;
  else if (minute >= 70 && diff === 1) contexto = `Gol que puede ser el de la victoria en la recta final.`;
  else if (diff >= 3)         contexto = `El dominio del equipo ${team} queda reflejado en el marcador.`;
  else                        contexto = `El equipo ${team} amplГӯa la ventaja y administra el partido.`;
  return `${accion} ${contexto}`;
}

function contextLabel(minute, hs, as_, detail) {
  if (detail === 'Own Goal')  return null;
  if (minute <= 10)           return 'рҹҡҖ Gol tempranero';
  if (minute >= 86)           return 'рҹ”Ҙ Gol sobre la bocina';
  if (hs === as_)             return 'рҹ”„ Gol del empate';
  const diff = Math.abs(hs - as_);
  if (diff === 1 && hs + as_ === 1) return 'рҹ”“ Se abre el marcador';
  if (minute >= 70 && diff === 1)   return 'рҹҸҶ Gol decisivo';
  if (diff >= 3)                    return 'рҹ“Ҳ Goleada en camino';
  return 'вҡЎ El marcador se mueve';
}

function goalLine(e, fid) {
  const f      = flag(e.team?.name || '');
  const isOG   = e.detail === 'Own Goal';
  const isPen  = e.detail === 'Penalty';
  const player = expandName(fid, e.player?.name) || '?';
  const assist = expandName(fid, e.assist?.name);
  const min    = minStr(e);
  let line = isOG ? `рҹҳ¬ ${player}  ${min}  В· OG` : `${f} ${player}  ${min}${isPen ? '  В· Pen' : ''}`;
  if (assist) line += `\nрҹ…° ${assist}`;
  return line;
}

function mvp(goals, fid) {
  const c = {};
  for (const g of goals) {
    if (g.detail === 'Own Goal') continue;
    const p = expandName(fid, g.player?.name), a = expandName(fid, g.assist?.name);
    if (p) c[p] = (c[p] || 0) + 2;
    if (a) c[a] = (c[a] || 0) + 1;
  }
  const s = Object.entries(c).sort((a,b) => b[1] - a[1]);
  return s.length ? s[0][0] : null;
}

const ALLOWED_L = [1, 10];

for (const fix of fixtures) {
  if (!ALLOWED_L.includes(fix.league?.id)) continue;

  const id      = String(fix.fixture.id);
  const status  = fix.fixture.status?.short || '';
  const elapsed = fix.fixture.status?.elapsed || 0;
  const home    = fix.teams?.home?.name  || 'Local';
  const away    = fix.teams?.away?.name  || 'Visitante';
  const fH      = flag(home);
  const fA      = flag(away);
  const prev = sd[id] || {
    hs:0, as_:0, status:'NS',
    kickoffSent:false, lineupSent:false,
    htSent:false, h2Sent:false, ftSent:false
  };
  let holdGoal = false;
  // Si la API trae goles null (transiciГіn de estado), usar el Гәltimo marcador conocido
  const hs      = fix.goals?.home  ?? prev.hs ?? 0;
  const as_     = fix.goals?.away  ?? prev.as_ ?? 0;
  const venue   = fix.fixture?.venue?.name || '';
  const league  = fix.league?.name || 'Internacional';
  const fixEvts = fix.events || [];



  // в”Җв”Җ Marcador inline в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  const score = `${fH} ${home}  ${hs} вҖ“ ${as_}  ${away} ${fA}`;

  // в”Җв”Җ 1. KICKOFF в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (status === '1H' && !['1H','2H','HT','ET'].includes(prev.status) && !prev.kickoffSent) {
    const lines = [
      'рҹҹў ВЎPARTIDO INICIADO!',
      '',
      `${fH} ${home}  0 вҖ“ 0  ${away} ${fA}`,
      '',
      `рҹ“… ${league}`,
      venue ? `рҹҸҹ ${venue}` : null,
      '',
      'вҸұ En curso  В·  #RODAI Sport'
    ].filter(l => l !== null);
    const msg = lines.join('\n');
    events.push({ partido_id:id, tipo:'kickoff', detalle:`ko_${id}`,
      home, away, venue, elapsed:0, msg_wa:msg, msg_tg:msg });
  }

  // в”Җв”Җ 2. ALINEACIONES в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (status === '1H' && elapsed >= 1 && elapsed <= 5 && !prev.lineupSent) {
    events.push({ partido_id:id, tipo:'lineup', detalle:`lu_${id}`,
      home, away, venue, elapsed,
      msg_wa:'LINEUP_PENDING', msg_tg:'LINEUP_PENDING' });
  }

  // в”Җв”Җ 3. GOLES в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if ((hs > prev.hs || as_ > prev.as_) && ['1H','2H','ET'].includes(status)) {
    const goalEvts = fixEvts.filter(e => e.type === 'Goal');
    const last     = goalEvts[goalEvts.length - 1] || {};
    const scoring  = last.team?.name || (hs > prev.hs ? home : away);
    const scorer   = expandName(id, last.player?.name) || '?';
    const assist   = expandName(id, last.assist?.name) || null;
    const detail   = last.detail || 'Normal Goal';
    const goalMin  = last.time?.elapsed || elapsed;
    const extra    = last.time?.extra || null;
    const minFull  = extra ? `${goalMin}+${extra}'` : `${goalMin}'`;
    const isOG     = detail === 'Own Goal';
    const isPen    = detail === 'Penalty';
    const narrative = buildNarrative(scorer, assist, detail, goalMin, scoring, home, away, hs, as_);
    const ctxLabel  = contextLabel(goalMin, hs, as_, detail);
    const fScoring  = flag(scoring);

    const lines = [
      `рҹҡЁ GOOOL DE ${scoring.toUpperCase()}`,
      '',
      `${fH} ${home}  ${hs} вҖ“ ${as_}  ${away} ${fA}`,
      ''
    ];

    if (isOG)      lines.push(`рҹҳ¬ ${scorer}  ${minFull}  В· OG`);
    else if (isPen) lines.push(`вҡҪ ${scorer}  ${minFull}  В· Pen`);
    else            lines.push(`вҡҪ ${scorer}  ${minFull}`);

    if (assist) lines.push(`рҹ…° ${assist}`);

    lines.push('', narrative);
    if (ctxLabel) lines.push('', ctxLabel);
    lines.push('', `вҸұ ${minFull}  В·  #RODAI Sport`);

    const msg = lines.join('\n');
    if (scorer === '?' && (prev.goalRetry || 0) < 2) {
      // El marcador subio pero aun no hay goleador: FLASH inmediato + narracion cuando llegue el nombre
      holdGoal = true;
      if ((prev.goalRetry || 0) === 0) {
        const flashMsg = [
          `рҹҡЁ ВЎGOOOOL DE ${scoring.toUpperCase()}!`, '',
          `${fH} ${home}  ${hs} вҖ“ ${as_}  ${away} ${fA}`, '',
          `вҸұ ${minFull} В· En segundos te contamos quiГ©n anotГі вҡҪ`, '',
          `#RODAI Sport`].join('\n');
        events.push({ partido_id:id, tipo:'goal_flash', detalle:`flash_${id}_${hs}_${as_}`,
          home, away, hs, as_, msg_wa:flashMsg, msg_tg:flashMsg });
      }
    } else {
      events.push({ partido_id:id, tipo:'goal', detalle:`goal_${id}_${hs}_${as_}`,
        home, away, hs, as_, scorer, assist, detail, elapsed: goalMin, narrative,
        msg_wa:msg, msg_tg:msg });
    }
  }

  // в”Җв”Җ 3a. CORRECCIГ“N VAR: el marcador BAJA (gol anulado tras revisiГіn) в”Җв”Җв”Җв”Җв”Җв”Җ
  // Solo es bajada si la API trae un NГҡMERO menor que prev (null = transiciГіn, NO bajada)
  const rawH = fix.goals?.home;
  const rawA = fix.goals?.away;
  const scoreDropped = (typeof rawH === 'number' && rawH < prev.hs) ||
                       (typeof rawA === 'number' && rawA < prev.as_);
  if (scoreDropped && ['1H','2H','ET','HT','BT','P'].includes(status)) {
    const mAnul = [
      'рҹҡ« GOL ANULADO', '',
      'El tanto no sube al marcador вҖ” revisiГіn del VAR', '',
      `${fH} ${home}  ${hs} вҖ“ ${as_}  ${away} ${fA}`, '',
      `вҸұ ${elapsed}'  В·  #RODAI Sport`
    ].join('\n');
    events.push({ partido_id:id, tipo:'var_anulado', detalle:`anul_${id}_${hs}_${as_}_${elapsed}`,
      home, away, hs, as_, elapsed, msg_wa:mAnul, msg_tg:mAnul });
    // prev.hs/as_ se actualizan al final via sd[id] = { hs, as_, ... } (holdGoal=false en bajadas)
  }

  // в”Җв”Җ 3b. EVENTOS ESPECIALES: expulsiones, VAR, penales в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  const seenEvts = prev.evtSeen || [];
  const curSigs = [];
  for (const ev of fixEvts) {
    const sig = `${ev.type}|${ev.detail}|${ev.time?.elapsed||0}|${(ev.player?.name)||''}`;
    curSigs.push(sig);
    if (seenEvts.includes(sig)) continue;
    if (!['1H','2H','ET','HT','BT','P'].includes(status)) continue;
    const minE = `${ev.time?.elapsed||elapsed}'`;
    const fEv  = flag(ev.team?.name || '');
    const pl   = ev.player?.name || '';
    let tipoE = null, m = null;
    if (ev.type === 'Card' && ev.detail === 'Red Card') {
      tipoE = 'roja';
      m = [`рҹҹҘ ВЎEXPULSIГ“N!`, '', `${fEv} ${ev.team?.name} se queda con uno menos`, '',
           `рҹ‘Ө ${pl || 'Jugador'} ve la roja al ${minE}`, '', score, '', `#RODAI Sport`].join('\n');
    } else if (ev.type === 'Var') {
      const det = (ev.detail || '').toLowerCase();
      if (det.includes('cancelled') || det.includes('disallowed')) {
        tipoE = 'var_anulado';
        m = [`рҹҡ« GOL ANULADO POR EL VAR`, '', `${fEv} ${ev.team?.name}${pl ? ' вҖ” el tanto de ' + pl : ''} no sube al marcador (${minE})`, '', score, '', `#RODAI Sport`].join('\n');
      } else if (det.includes('penalty confirmed') || det.includes('penalty awarded')) {
        tipoE = 'var_penal';
        m = [`вҡ пёҸ ВЎPENAL! Confirmado por el VAR`, '', `${fEv} A favor de ${ev.team?.name} al ${minE}`, '', score, '', `#RODAI Sport`].join('\n');
      }
    } else if (ev.type === 'Goal' && ev.detail === 'Missed Penalty') {
      tipoE = 'penal_fallado';
      m = [`рҹҳұ ВЎPENAL FALLADO!`, '', `${fEv} ${pl || 'El cobrador'} no pudo convertir al ${minE}`, '', score, '', `#RODAI Sport`].join('\n');
    }
    if (tipoE && m) {
      events.push({ partido_id:id, tipo:tipoE, detalle:('sp_'+id+'_'+sig).slice(0,190),
        home, away, hs, as_, msg_wa:m, msg_tg:m });
    }
  }

  // в”Җв”Җ 4. FIN PRIMER TIEMPO в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (status === 'HT' && !prev.htSent) {
    const goalsHT  = fixEvts.filter(e => e.type==='Goal' && (e.time?.elapsed||0) <= 45);
    const lines    = [
      'вҸё DESCANSO',
      '',
      `${fH} ${home}  ${hs} вҖ“ ${as_}  ${away} ${fA}`
    ];
    if (goalsHT.length) {
      lines.push('');
      goalsHT.forEach(g => lines.push(goalLine(g, id)));
    }
    lines.push('', `вҸұ Fin del primer tiempo  В·  #RODAI Sport`);
    events.push({ partido_id:id, tipo:'halftime', detalle:`ht_${id}_${hs}_${as_}`,
      home, away, msg_wa:lines.join('\n'), msg_tg:lines.join('\n') });
  }

  // в”Җв”Җ 5. INICIO 2DO TIEMPO в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (status === '2H' && prev.status === 'HT' && !prev.h2Sent) {
    const msg = [
      'в–¶пёҸ SEGUNDO TIEMPO',
      '',
      `${fH} ${home}  ${hs} вҖ“ ${as_}  ${away} ${fA}`,
      '',
      `вҸұ Segunda mitad iniciada  В·  #RODAI Sport`
    ].join('\n');
    events.push({ partido_id:id, tipo:'h2_start', detalle:`h2_${id}`,
      home, away, msg_wa:msg, msg_tg:msg });
  }

  // в”Җв”Җ 6. RESULTADO FINAL в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (['FT','AET','PEN'].includes(status) && !prev.ftSent && home !== 'Local' && away !== 'Visitante') {
    const allGoals = fixEvts.filter(e => e.type === 'Goal');
    const allCards = fixEvts.filter(e => e.type === 'Card');
    const winner   = hs > as_ ? home : as_ > hs ? away : null;
    const mvpName  = mvp(allGoals, id);

    const lines = [
      'рҹҸҒ RESULTADO FINAL',
      '',
      `${fH} ${home}  ${hs} вҖ“ ${as_}  ${away} ${fA}`
    ];

    if (allGoals.length) {
      lines.push('');
      allGoals.forEach(g => lines.push(goalLine(g, id)));
    }

    const yellowCards = allCards.filter(c => c.detail === 'Yellow Card');
    const redCards    = allCards.filter(c => c.detail === 'Red Card');
    if (yellowCards.length + redCards.length > 0) {
      lines.push('');
      yellowCards.forEach(c => lines.push(`рҹҹЁ ${expandName(id, c.player?.name)}  ${minStr(c)}`));
      redCards.forEach(c => lines.push(`рҹҹҘ ${expandName(id, c.player?.name)}  ${minStr(c)}`));
    }

    lines.push('');
    if (mvpName) lines.push(`вӯҗ MVP: ${mvpName}`);
    lines.push(winner ? `рҹҸҶ Ganador: ${winner}` : 'рҹӨқ Empate');
    lines.push('');
    lines.push(`рҹ“… ${league}  В·  вҸұ Finalizado`);
    lines.push('#RODAI Sport');

    const nxt = getNextMx();
    if (nxt) {
      lines.push('');
      lines.push('в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ');
      lines.push('рҹ“… PRГ“XIMO PARTIDO');
      lines.push('');
      lines.push(nxt.hf + ' ' + nxt.h + ' vs ' + nxt.a + ' ' + nxt.af);
      lines.push(nxt.d + ' В· {{HORA_PROXIMO}}');
      lines.push('рҹҸҹпёҸ ' + nxt.v);
    }
    const ftMsg = lines.join('\n');

    events.push({ partido_id:id, tipo:'fulltime', detalle:`ft_${id}_${hs}_${as_}`,
      home, away,
      next_match_utc_ts: nxt ? nxt.utc_ts : 0,
      msg_wa:ftMsg, msg_tg:ftMsg });
    globalSd['ftdone_' + id] = { ts: Date.now(), home, away, hs, as_ };
  }

  sd[id] = {
    hs: holdGoal ? prev.hs : hs,
    as_: holdGoal ? prev.as_ : as_,
    goalRetry: holdGoal ? (prev.goalRetry || 0) + 1 : 0,
    evtSeen: curSigs,
    home, away, missing: 0,
    status,
    kickoffSent : prev.kickoffSent || (status==='1H' && !['1H','2H','HT','ET'].includes(prev.status)),
    lineupSent  : prev.lineupSent  || (status==='1H' && elapsed>=1 && elapsed<=5),
    htSent      : prev.htSent      || (status==='HT'),
    h2Sent      : prev.h2Sent      || (status==='2H' && prev.status==='HT'),
    ftSent      : prev.ftSent      || ['FT','AET','PEN'].includes(status)
  };
}

// в”Җв”Җ FT POR DESAPARICIГ“N: el partido saliГі de live=all sin pasar por FT visible в”Җв”Җ
const liveIds = new Set(fixtures.filter(f => ALLOWED_L.includes(f.league?.id)).map(f => String(f.fixture.id)));
for (const sid of Object.keys(sd)) {
