    .map(p => (nameMap[p.player?.name] || p.player?.name || ''))
    .filter(Boolean).join('  В·  ');
  return [`${f} ${t.team?.name} (${t.formation||'?'})  В·  DT: ${t.coach?.name||'?'}`, xi].join('\n');
}

