const koMs = new Date(fx.fixture.date).getTime();
const cal  = PARTIDOS.find(p => new Date(p.utc).getTime() === koMs) || null;
const home  = cal ? cal.home : apiHome;
const away  = cal ? cal.away : apiAway;
const venue = (cal && cal.venue) || fx.fixture?.venue?.name || '';
const city  = (cal && cal.city)  || fx.fixture?.venue?.city || '';
const grupo = cal ? cal.group : '';
const fH = flag(home), fA = flag(away);

// Mapea nombre de equipo API вҶ’ ES para etiquetas de goles
function teamES(n) { if (n === apiHome) return home; if (n === apiAway) return away; return n; }

const evts = fx.events || [];
const goles = evts.filter(e => e.type === 'Goal' && e.detail !== 'Missed Penalty');
const varAnulados = evts.filter(e => e.type === 'Var' && /cancell|disallow/i.test(e.detail || ''));

const lines = ['рҹҸҶ RESUMEN FINAL вҖ” MUNDIAL 2026', ''];
lines.push(`${fH} ${home} ${hs} вҖ“ ${as_} ${away} ${fA}`);
if (venue) lines.push(`рҹ“Қ ${venue}${city ? ', ' + city : ''}`);
lines.push(`вҡҪ Fase de Grupos${grupo ? ' В· Grupo ' + grupo : ''}`);

if (goles.length || varAnulados.length) {
  lines.push('', 'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'вҡҪ GOLES', '');
  for (const gl of goles) {
    const min = gl.time?.extra ? `${gl.time.elapsed}+${gl.time.extra}` : `${gl.time?.elapsed || '?'}`;
    const quien = gl.player?.name || '?';
    const eq = teamES(gl.team?.name || '');
    const tag = gl.detail === 'Own Goal' ? ' (autogol)' : (gl.detail === 'Penalty' ? ' (penal)' : '');
    lines.push(`вҡҪ min. ${min}' вҖ” ${quien}${tag} (${eq})`);
    if (gl.assist?.name) lines.push(`   Asistencia: ${gl.assist.name}`);
  }
  for (const va of varAnulados) {
    const min = va.time?.elapsed || '?';
    lines.push(`рҹҡ« min. ${min}' вҖ” Gol de ${teamES(va.team?.name || '?')} ANULADO por el VAR${va.detail ? ' (' + va.detail + ')' : ''}`);
  }
}

// в”Җв”Җ EstadГӯsticas в”Җв”Җ
function statOf(teamName, type) {
  const blk = (fx.statistics || []).find(s => s.team?.name === teamName);
  if (!blk) return null;
  const st = (blk.statistics || []).find(x => x.type === type);
  return st ? st.value : null;
}
const posH = statOf(apiHome, 'Ball Possession'), posA = statOf(apiAway, 'Ball Possession');
const shH = statOf(apiHome, 'Total Shots'), shA = statOf(apiAway, 'Total Shots');
const sogH = statOf(apiHome, 'Shots on Goal'), sogA = statOf(apiAway, 'Shots on Goal');
const fH_ = statOf(apiHome, 'Fouls'), fA_ = statOf(apiAway, 'Fouls');

if (posH || shH || fH_) {
  lines.push('', 'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'рҹ“Ҡ EN NГҡMEROS');
  if (posH !== null && posA !== null) {
    lines.push('', 'вҡҪ ВҝQuiГ©n tuvo mГЎs el balГіn?');
    lines.push(`   ${home} ${posH} В· ${away} ${posA}`);
  }
  if (shH !== null || shA !== null) {
    lines.push('', 'рҹҺҜ ВҝQuiГ©n llegГі mГЎs al arco?');
    lines.push(`   ${home}: ${shH ?? 0} remates, ${sogH ?? 0} al arco`);
    lines.push(`   ${away}: ${shA ?? 0} remates, ${sogA ?? 0} al arco`);
  }
  if (fH_ !== null || fA_ !== null) {
    lines.push('', 'рҹ”Ҙ ВҝQuiГ©n jugГі mГЎs agresivo?');
    lines.push(`   Faltas cometidas: ${home} ${fH_ ?? 0} В· ${away} ${fA_ ?? 0}`);
  }
}

// в”Җв”Җ CrГіnica (cГіdigo simple) в”Җв”Җ
const cron = [];
if (goles.length) {
  const primero = goles[0];
  const eqPri = primero.detail === 'Own Goal'
    ? teamES(primero.team?.name === apiHome ? apiAway : apiHome)
    : teamES(primero.team?.name || '');
  cron.push(`${eqPri} abriГі el marcador al minuto ${primero.time?.elapsed || '?'} con gol de ${primero.player?.name || '?'}.`);
  // remontada / empate
  let h = 0, a = 0, lider = null, remontada = false;
  for (const gl of goles) {
    const esLocal = gl.detail === 'Own Goal' ? gl.team?.name !== apiHome : gl.team?.name === apiHome;
    if (esLocal) h++; else a++;
    const nuevo = h > a ? 'H' : (a > h ? 'A' : null);
    if (lider && nuevo && nuevo !== lider) remontada = true;
    if (nuevo) lider = nuevo;
  }
  if (remontada) cron.push(`Hubo remontada: el partido cambiГі de dueГұo y terminГі ${hs} вҖ“ ${as_}.`);
  else if (hs === as_) cron.push(`Las acciones terminaron igualadas ${hs} вҖ“ ${as_}.`);
  else cron.push(`${hs > as_ ? home : away} controlГі el resultado y se llevГі los tres puntos.`);
  // figura
  const pts = {};
  for (const gl of goles) {
    if (gl.detail === 'Own Goal') continue;
    if (gl.player?.name) pts[gl.player.name] = (pts[gl.player.name] || 0) + 2;
    if (gl.assist?.name) pts[gl.assist.name] = (pts[gl.assist.name] || 0) + 1;
  }
  const fig = Object.entries(pts).sort((x, y) => y[1] - x[1])[0];
  if (fig) cron.push(`Figura del partido: ${fig[0]}.`);
} else {
  cron.push(`Empate sin goles: dominaron las defensas y los arqueros respondieron cuando fue necesario.`);
}
lines.push('', 'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'вңҚпёҸ CRГ“NICA', '', cron.join(' '));

lines.push('', 'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'рҹ“Ј ВҝCГіmo te pareciГі el servicio hoy?', 'Califica del 1 al 5 рҹ‘Ү');

const msg = lines.join('\n');
return [{ json: {
  partido_id: id, tipo: 'resumen_final', detalle: `resfinal_${id}`,
  home, away, hs, as_, msg_wa: msg, msg_tg: msg, events_count: 1
} }];
